using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tool implementations ---
var notebook = new Notebook();

// --- Build the agent ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the web_search tool to find relevant information. Search multiple queries to get comprehensive coverage.
        2. Use the save_note tool to save key findings as you go — include the source URL.
        3. After gathering enough information (at least 2-3 searches), use the get_notes tool to review your notes.
        4. Provide a final summary of your research findings, citing sources.
        Be thorough but concise. Focus on factual, well-sourced information.
        """,
    tools:
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync, "web_search",
            "Searches the web for a query and returns a list of result snippets with URLs."),
        AIFunctionFactory.Create(notebook.SaveNote, "save_note",
            "Saves a research note with a title and content for later reference."),
        AIFunctionFactory.Create(notebook.GetNotes, "get_notes",
            "Retrieves all saved research notes."),
    ]);

agent.ChatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
};

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrEmpty(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions { MaxOutputTokens = 4096 },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (update.Role == ChatRole.Assistant)
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Research complete. {notebook.Count} note(s) saved during research.");

// --- Tool classes ---

/// <summary>Simulated web search using DuckDuckGo Lite.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Searches the web and returns result snippets with URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            // Use DuckDuckGo Lite HTML endpoint
            var url = $"https://lite.duckduckgo.com/lite/?q={Uri.EscapeDataString(query)}";
            var html = await s_http.GetStringAsync(url);

            var results = ParseDdgResults(html);

            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}");
            sb.AppendLine();

            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"• {title}");
                if (!string.IsNullOrEmpty(snippet))
                    sb.AppendLine($"  {snippet}");
                if (!string.IsNullOrEmpty(link))
                    sb.AppendLine($"  URL: {link}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseDdgResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Parse result links from DuckDuckGo Lite HTML
        var linkSpans = html.Split(["class=\"result-link\""], StringSplitOptions.None);
        for (int i = 1; i < linkSpans.Length && results.Count < 5; i++)
        {
            var span = linkSpans[i];
            var href = ExtractAttribute(span, "href");
            var title = ExtractTagContent(span);

            // Try to find the snippet (next td with class="result-snippet")
            var snippet = "";
            var snippetIdx = span.IndexOf("result-snippet", StringComparison.Ordinal);
            if (snippetIdx >= 0)
            {
                snippet = ExtractTagContent(span[snippetIdx..]);
            }

            if (!string.IsNullOrEmpty(title) && !string.IsNullOrEmpty(href))
            {
                results.Add((
                    System.Net.WebUtility.HtmlDecode(title.Trim()),
                    System.Net.WebUtility.HtmlDecode(snippet.Trim()),
                    href.Trim()));
            }
        }

        // Fallback: parse <a> tags with hrefs that look like external URLs
        if (results.Count == 0)
        {
            var parts = html.Split(["<a "], StringSplitOptions.None);
            foreach (var part in parts.Skip(1))
            {
                var href = ExtractAttribute(part, "href");
                if (href != null && href.StartsWith("http") && !href.Contains("duckduckgo"))
                {
                    var title = ExtractTagContent(part);
                    if (!string.IsNullOrWhiteSpace(title))
                    {
                        results.Add((
                            System.Net.WebUtility.HtmlDecode(title.Trim()),
                            "",
                            href.Trim()));
                        if (results.Count >= 5) break;
                    }
                }
            }
        }

        return results;
    }

    private static string? ExtractAttribute(string html, string attr)
    {
        var search = $"{attr}=\"";
        var idx = html.IndexOf(search, StringComparison.OrdinalIgnoreCase);
        if (idx < 0) return null;
        idx += search.Length;
        var end = html.IndexOf('"', idx);
        return end < 0 ? null : html[idx..end];
    }

    private static string ExtractTagContent(string html)
    {
        var start = html.IndexOf('>');
        if (start < 0) return "";
        start++;
        var end = html.IndexOf('<', start);
        return end < 0 ? "" : html[start..end];
    }
}

/// <summary>Simple in-memory notebook for saving research notes.</summary>
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Saves a research note.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (note #{_notes.Count})";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content) = _notes[i];
            sb.AppendLine($"[Note #{i + 1}] {title}");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

