152.     {
153.         var results = new List<(string, string, string)>();
154. 
155.         // Parse result links from DuckDuckGo Lite HTML
156.         var linkSpans = html.Split(["class=\"result-link\""], StringSplitOptions.None);
157.         for (int i = 1; i < linkSpans.Length && results.Count < 5; i++)
158.         {
