180.         // Fallback: parse <a> tags with hrefs that look like external URLs
181.         if (results.Count == 0)
182.         {
183.             var parts = html.Split(["<a "], StringSplitOptions.None);
184.             foreach (var part in parts.Skip(1))
185.             {
186.                 var href = ExtractAttribute(part, "href");
